_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
   ret = texture( sampler_rand00, vUv);

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uvo = vUv*uAspect.xy;
vUv = vUv - .1*vec2(q5,q6);
vec2 uv1 = (vUv-.5)*uAspect.xy;

//Kugel1
rsk1 = (uv1 + vec2 (q9,q10)) ;
dz1 = normalize(rsk1);
rad1 = q11*length(rsk1) ;
uv4 =  sin(-rad1)*dz1;
mask1 = clamp01(7-10*rad1);
Kugel1 = uv4*mask1;

//Kugel2
rsk2 = (uv1 + vec2 (q13,q14)) ;
dz2 = normalize(rsk2);
rad2 = q15*length(rsk2) ;
uv4 =  sin(-rad2)*dz2;
mask2 = clamp01(7-10*rad2);
Kugel2 = uv4*mask2;

//Kugel3
rsk3 = (uv1 + vec2 (q17,q18)) ;
dz3 = normalize(rsk3);
rad3 = q19*length(rsk3) ;
uv4 =  sin(-rad3)*dz3;
mask3 = clamp01(7-10*rad3);
Kugel3 = uv4*mask3;

//Ring
rsk4 = vec2(length(uv1)-.22,0) ;
dz4 = normalize(rsk4);
rad4 = q19*length(rsk4) ;
uv4 =  sin(-rad4)*dz4;
mask4 = clamp01(3-10*rad4);
Ring = uv4*mask4*0;

vec2 dz = (Kugel2 + Kugel1 + Kugel3 + Ring)*.2;

//******************** STARS
uv1 -= dz;
rss0.x = atan(uv1.x, uv1.y)/3.1416;
rss0.y = .015/(length(uv1));

rss = vec2 (rss0.x,rss0.y+uTime/4);
rss = multiply(rss,mat2(.7,.7,-.7,.7));
float noise = (texture(sampler_pw_noise_lq,rss/32)-.9 >= 0);
tmp = abs(fract(rss*8)-.5);
vec3 dots = clamp01(.04/length(tmp)) *noise;

dots *= clamp01(.2/abs(rss0.y));
dots = clamp01(lum(dots)*lum(dots)*1);
k1 = lum(dots);
dots= k1*vec3(1,k1*.8,k1*k1/3)  ;

//*************************
float z = .2/(length(uv1)+q21);
uv2.y = z + q8;
uv2.x = rss0.x +q7;
uv3 =fract(uv2*2);
cathed =  texture(sampler_main,uv3)/z;
float cmask = clamp01(1-32*GetBlur1(uv3));

dz1 = normalize(multiply(dz1,mat2(-q9,q10,-q10,-q9)))+.5;
dz2 = normalize(multiply(dz2,mat2(-q13,q14,-q14,-q13)))+.5;
dz3 = normalize(multiply(dz3,mat2(-q17,q18,-q18,-q17)))+.5;

vec3 mod = 1*vec3(.7,.3,1)* sin(uTime/7);
vec3 blk = (dz1.x/rad1 + dz2.x/rad2 + dz3.x/rad3) *mod;
blk = clamp01(blk);

//Feuer:
float feu = .1+q22;
fire = clamp01(.03*feu/length(uv1)*
 (lum(GetBlur2(uv3-vec2(0,0))))) ;

//Tasaechl. Feuer; Problem: uv1 passt nicht zu uv3
vec2 uvf = uv1+.0;
fire += clamp01(.001*feu/length(uvf)*
 (lum(texture(sampler_main,uvf+.5)))-.01)
* (1/length(uvf));

k1 = lum(fire);
fire = k1*vec3(1,k1,k1*k1/3) ;

vec2 uvs = 32*uvo;
vec3 smask = (texture(sampler_pw_noise_lq,uvs/256)).g-.9;
float stars = clamp01(.3/length(abs(fract(uvs)-.5))*smask);

vec3 moon = clamp01(.02/length(uvo-.2));
sky = stars*stars * clamp01(1-4*moon) + moon ;

ret += sky*(cmask);
ret += fire+dots;

ret += clamp01(.0+moon+blk)*cathed + blk;

  fragColor = ret;
}
